mapper.select:
with scenario_years as ( select sc.agristability_scenario_id, py.year as reference_year from farms.farm_agristability_scenarios sc join farms.farm_program_year_versions pyv on pyv.program_year_version_id = sc.program_year_version_id join farms.farm_program_years py on py.program_year_id = pyv.program_year_id where sc.agristability_scenario_id = #{agristabilityScenarioId}
union
select ref_sc.agristability_scenario_id, ref_py.year as reference_year from farms.farm_reference_scenarios rs join farms.farm_agristability_scenarios ref_sc on ref_sc.agristability_scenario_id = rs.agristability_scenario_id join farms.farm_program_year_versions ref_pyv on ref_pyv.program_year_version_id = ref_sc.program_year_version_id join farms.farm_program_years ref_py on ref_py.program_year_id = ref_pyv.program_year_id where rs.for_agristability_scenario_id = #{agristabilityScenarioId} ), productive_unit_flags as ( select sy.agristability_scenario_id, case when count(puc.productve_unit_capacity_id) filter ( where coalesce(puc.productive_capacity_amount, 0) <> 0 ) > 0 then 'Y' else 'N' end as has_productive_units_ind from scenario_years sy left join farms.farm_productve_unit_capacities puc on puc.agristability_scenario_id = sy.agristability_scenario_id group by sy.agristability_scenario_id ) select sy.reference_year, bct.production_marg_accr_adjs as production_margin_accrual_adjustments, bct.production_marg_aft_str_changs as production_margin_after_structural_changes, bct.total_allowable_income, bct.total_unallowable_expenses, puf.has_productive_units_ind from scenario_years sy join farms.farm_benefit_calc_totals bct on bct.agristability_scenario_id = sy.agristability_scenario_id left join productive_unit_flags puf on puf.agristability_scenario_id = sy.agristability_scenario_id order by sy.reference_year
